export type SkuCategory = "tech" | "home" | "lifestyle" | "accessories" | "stationery" | "apparel";
export type SkuStatus = "out" | "low" | "healthy" | "dead";
export type SkuVerdict = "reorder" | "watch" | "hold" | "liquidate";
export type SkuBand = "working" | "slow" | "thin" | "trapped";

export interface InventoryItem {
  name: string;
  sku: string;
  category: SkuCategory;
  /** Units on hand */
  qty: number;
  /** Units per day */
  vel: number;
  /** Units in transit (incoming) */
  transit: number;
  /** Units on order (not yet shipped) */
  onorder: number;
  /** Days */
  lead: number;
  /** Landed-cost components: [supplier, freight, duties, handling, storage] */
  costComponents: [number, number, number, number, number];
  /** Contribution margin level 1, % */
  cm1: number;
  /** Contribution margin level 3, % */
  cm3: number;
  /** Revenue at risk if it stocks out, $ */
  revAtRisk: number;
  status: SkuStatus;
  verdict: SkuVerdict;
  band: SkuBand;
}

