export interface DerivedItem extends InventoryItem {
  landed: number;
  value: number;
  cover: number;
}

export function deriveItem(d: InventoryItem): DerivedItem {
  const landed = d.costComponents.reduce((a, b) => a + b, 0);
  return {
    ...d,
    landed,
    value: d.qty * landed,
    cover: d.vel > 0 ? (d.qty + d.transit + d.onorder) / d.vel : 9999,
  };
}

